// Patch v2 — Corrige l'ergonomie de PauseFigeeSection :
// (1) le bouton "Ajouter une journée" est sorti de l'en-tête (il entrait en
//     conflit avec le clic d'ouverture/fermeture de l'accordéon, empêchant
//     de rouvrir via la flèche une fois refermé) — il vit maintenant DANS le
//     contenu déplié, en haut, comme un vrai bouton pleine largeur ;
// (2) tailles de police et de boutons encore augmentées pour la lisibilité
//     sur ordinateur (cases du calendrier, libellés de journée, menu FIA,
//     boutons FIA?/×).
//
// Usage : node patch_pausefigee_v2_ergonomie.js
// À exécuter depuis : C:\Users\olive\Desktop\f2p-pmp
// PRÉREQUIS : avoir déjà exécuté patch_pausefigee_appjsx.js

const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'src', 'App.jsx');

const OLD_B64 = "";
const NEW_B64 = "";

const oldBlock = Buffer.from(OLD_B64, 'base64').toString('utf-8');
const newBlock = Buffer.from(NEW_B64, 'base64').toString('utf-8');

let content = fs.readFileSync(FILE).toString('utf-8');

const count = content.split(oldBlock).length - 1;
if (count === 0) throw new Error('[PauseFigeeSection v2] Ancre introuvable dans ' + FILE + ' — as-tu bien exécuté patch_pausefigee_appjsx.js avant celui-ci ?');
if (count > 1) throw new Error('[PauseFigeeSection v2] Ancre trouvée ' + count + ' fois (doit être unique) dans ' + FILE);

content = content.replace(oldBlock, newBlock);

fs.writeFileSync(FILE, content, 'utf-8');
console.log('OK — App.jsx patché (PauseFigeeSection v2 : bouton déplacé, tailles augmentées)');
